/**
 * Slots for the DropdownMenuCheckbox component.
 */
export type DropdownMenuCheckboxSlots<T extends DefinedValue = DefinedValue> = DropdownMenuCheckboxCompactSlots<T>;

// Menu Radio
/**
 * Properties for the DropdownMenuRadio component.
 */
export type DropdownMenuRadioProps<T extends AcceptableBooleanValue = AcceptableBooleanValue> = MenuUiBaseProps &
  DropdownMenuRadioCompactProps<T>;

/**
 * Events for the DropdownMenuRadio component.
 */
export type DropdownMenuRadioEmits<T extends AcceptableBooleanValue = AcceptableBooleanValue> =
  DropdownMenuRadioCompactEmits<T>;

/**
 * Slots for the DropdownMenuRadio component.
 */
export type DropdownMenuRadioSlots<T extends AcceptableBooleanValue = AcceptableBooleanValue> =
  DropdownMenuRadioCompactSlots<T>;

import { computed, toValue } from 'vue';
import type { MaybeRefOrGetter } from 'vue';
import { provideMenuUi as _provideMenuUi } from '@soybeanjs/headless/menu';
import { menuVariants } from '@/styles/menu';
import type { MenuUiBaseProps } from './types';

export const provideMenuUi = (options: MaybeRefOrGetter<MenuUiBaseProps>) => {
  const ui = computed(() => {
    const props = toValue(options);

    return menuVariants(
      {
        size: props.size,
        indicatorPosition: props.indicatorPosition
      },
      props.ui,
      { popup: props.class }
    );
  });

  _provideMenuUi(ui);
};

import type { MenuUi } from '@soybeanjs/headless/menu';
import type { ClassValue, AlignSide } from '@soybeanjs/headless/types';
import type { ThemeSize } from '@/theme';

/**
 * Properties for the MenuUiBase component.
 */
export interface MenuUiBaseProps {
  /**
   * class of menu popup
   */
  class?: ClassValue;
  /**
   * Visual size of the component.
   */
  size?: ThemeSize;
  /**
   * Per-slot class overrides for the component.
   */
  ui?: Partial<MenuUi>;
  /**
   * Indicator position.
   */
  indicatorPosition?: AlignSide;
}

